import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [58, 27, 9, 4, 2],
    options: {
      chart: {
        type: 'donut',
      },
      labels: ['Mobile', 'Desktop', 'Tablet', 'Smart TV', 'Wearable'],
      title: {
        text: 'Sessions by Device',
        align: 'center',
      },
      plotOptions: {
        pie: {
          startAngle: -90,
          endAngle: 90,
          offsetY: 10,
          dataLabels: {
            external: {
              show: true,
              formatter: function (name, opts) {
                return [name, Math.round(opts.percent) + '%']
              },
            },
          },
        },
      },
      dataLabels: {
        enabled: false,
      },
      legend: {
        show: false,
      },
      grid: {
        padding: {
          bottom: -80,
        },
      },
      responsive: [
        {
          breakpoint: 480,
          options: {
            chart: {
              width: 300,
            },
          },
        },
      ],
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="donut"
        />
      </div>
    </div>
  )
}

export default ApexChart
